diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c06d5c759634..096ac3f33abc 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1168,6 +1168,95 @@ static Value *extractIntPart(const IntPart &P, IRBuilderBase &Builder) {
   if (TruncTy != V->getType())
     V = Builder.CreateTrunc(V, TruncTy);
   return V;
+  return V;
+}
+
+/// Fold (icmp eq X, C) | (icmp ult Y, (X - C)) -> icmp ule Y, (X - C - 1)
+/// Fold (icmp ne X, C) & (icmp uge Y, (X - C)) -> icmp ugt Y, (X - C - 1)
+/// This is valid because:
+/// - For OR: if X == C, the result is true. If X != C, then X - C != 0, and
+///   Y < X - C is equivalent to Y <= X - C - 1 (when X - C doesn't overflow).
+/// - For AND: if X == C, the result is false. If X != C, then X - C != 0, and
+///   Y >= X - C is equivalent to Y > X - C - 1 (when X - C doesn't overflow).
+static Value *foldMaxValueAndAddCheck(ICmpInst *EqICmp, ICmpInst *AddICmp,
+                                      bool IsAnd, const SimplifyQuery &Q,
+                                      InstCombiner::BuilderTy &Builder) {
+  // Match (icmp eq/ne X, C).
+  ICmpInst::Predicate EqPred;
+  Value *X;
+  const APInt *C;
+  if (!match(EqICmp, m_ICmp(EqPred, m_Value(X), m_APInt(C))))
+    return nullptr;
+
+  // For AND: need (icmp ne X, C)
+  // For OR: need (icmp eq X, C)
+  if (IsAnd && EqPred != ICmpInst::ICMP_NE)
+    return nullptr;
+  if (!IsAnd && EqPred != ICmpInst::ICMP_EQ)
+    return nullptr;
+
+  // Match (icmp ult/uge Y, (X - C)) or commuted versions.
+  ICmpInst::Predicate AddPred;
+  Value *Op0, *Op1;
+  if (!match(AddICmp, m_ICmp(AddPred, m_Value(Op0), m_Value(Op1))))
+    return nullptr;
+
+  // For AND: need (icmp uge Y, (X - C)) which is equivalent to (icmp ule (X - C), Y)
+  // For OR: need (icmp ult Y, (X - C)) which is equivalent to (icmp ugt (X - C), Y)
+  // Try to match with Op0 as Y and Op1 as (X - C).
+  Value *Y = Op0;
+  Value *AddOp = Op1;
+  
+  // Check if we need to swap (i.e., Op1 is Y and Op0 is (X - C)).
+  // We detect this by checking if the predicate makes sense.
+  // For AND: we need uge, which is swapped ule.
+  // For OR: we need ult, which is swapped ugt.
+  if (IsAnd) {
+    // For AND: need uge Y, (X - C). Check if we have ule (X - C), Y.
+    if (AddPred == ICmpInst::ICMP_ULE) {
+      std::swap(Y, AddOp);
+      AddPred = ICmpInst::getSwappedPredicate(AddPred);
+    }
+  } else {
+    // For OR: need ult Y, (X - C). Check if we have ugt (X - C), Y.
+    if (AddPred == ICmpInst::ICMP_UGT) {
+      std::swap(Y, AddOp);
+      AddPred = ICmpInst::getSwappedPredicate(AddPred);
+    }
+  }
+
+  // Now check the predicate.
+  if (IsAnd && AddPred != ICmpInst::ICMP_UGE)
+    return nullptr;
+  if (!IsAnd && AddPred != ICmpInst::ICMP_ULT)
+    return nullptr;
+
+  // Check that AddOp is (X + (-C)), i.e., X - C.
+  Value *X2;
+  const APInt *AddC;
+  if (!match(AddOp, m_Add(m_Value(X2), m_APInt(AddC))) || X2 != X)
+    return nullptr;
+
+  // Check that AddC == -C.
+  if (*AddC != -(*C))
+    return nullptr;
+
+  // Require at least one use to allow the fold.
+  if (!EqICmp->hasOneUse() && !AddICmp->hasOneUse())
+    return nullptr;
+
+  // Fold to (icmp ugt/ule Y, (X - C - 1)) or (icmp ule/ugt (X - C - 1), Y).
+  Type *Ty = X->getType();
+  APInt NewC = *AddC - 1;
+  Value *NewAdd = Builder.CreateAdd(X, ConstantInt::get(Ty, NewC));
+  
+  if (IsAnd) {
+    // (icmp ne X, C) & (icmp uge Y, (X - C)) -> icmp ugt Y, (X - C - 1)
+    return Builder.CreateICmp(ICmpInst::ICMP_UGT, Y, NewAdd);
+  } else {
+    // (icmp eq X, C) | (icmp ult Y, (X - C)) -> icmp uge (X - C - 1), Y
+    return Builder.CreateICmp(ICmpInst::ICMP_UGE, NewAdd, Y);
+  }
 }

 /// (icmp eq X0, Y0) & (icmp eq X1, Y1) -> icmp eq X01, Y01
@@ -3105,6 +3194,10 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
       return X;
     if (Value *X = foldUnsignedUnderflowCheck(RHS, LHS, IsAnd, Q, Builder))
       return X;
+    if (Value *X = foldMaxValueAndAddCheck(LHS, RHS, IsAnd, Q, Builder))
+      return X;
+    if (Value *X = foldMaxValueAndAddCheck(RHS, LHS, IsAnd, Q, Builder))
+      return X;
   }

   if (Value *X = foldEqOfParts(LHS, RHS, IsAnd))

