/// Fold (icmp ne X, C) & (icmp ule (X - C), Y) -> icmp ult (X - C - 1), Y
/// Fold (icmp eq X, C) | (icmp ugt (X - C), Y) -> icmp uge (X - C - 1), Y
/// This is valid because if X != C, then X - C doesn't overflow,
/// and X - C <= Y is equivalent to X - C - 1 < Y.
/// Similarly, if X == C, then X - C = 0, and the whole expression is false/true.
static Value *foldMaxValueAndAddCheck(ICmpInst *EqICmp, ICmpInst *AddICmp,
                                      bool IsAnd, const SimplifyQuery &Q,
                                      InstCombiner::BuilderTy &Builder) {
  // Match (icmp eq/ne X, C).
  ICmpInst::Predicate EqPred;
  Value *X;
  const APInt *C;
  if (!match(EqICmp, m_ICmp(EqPred, m_Value(X), m_APInt(C))))
    return nullptr;

  // For AND: need (icmp ne X, C)
  // For OR: need (icmp eq X, C)
  if (IsAnd && EqPred != ICmpInst::ICMP_NE)
    return nullptr;
  if (!IsAnd && EqPred != ICmpInst::ICMP_EQ)
    return nullptr;

  // Match (icmp ule/ugt (X - C), Y) for AND/OR respectively.
  ICmpInst::Predicate AddPred;
  Value *AddOp, *Y;
  if (!match(AddICmp, m_c_ICmp(AddPred, m_Value(AddOp), m_Value(Y))))
    return nullptr;

  // For AND: need (icmp ule (X - C), Y)
  // For OR: need (icmp ugt (X - C), Y)
  if (IsAnd && AddPred != ICmpInst::ICMP_ULE)
    return nullptr;
  if (!IsAnd && AddPred != ICmpInst::ICMP_UGT)
    return nullptr;

  // Check that AddOp is (X + (-C)), i.e., X - C.
  Value *X2;
  const APInt *AddC;
  if (!match(AddOp, m_Add(m_Value(X2), m_APInt(AddC))) || X2 != X)
    return nullptr;

  // Check that AddC == -C.
  if (*AddC != -(*C))
    return nullptr;

  // Require at least one use to allow the fold.
  if (!EqICmp->hasOneUse() && !AddICmp->hasOneUse())
    return nullptr;

  // Fold to (icmp ult/uge (X - C - 1), Y).
  Type *Ty = X->getType();
  APInt NewC = *AddC - 1;
  Value *NewAdd = Builder.CreateAdd(X, ConstantInt::get(Ty, NewC));
  ICmpInst::Predicate NewPred = IsAnd ? ICmpInst::ICMP_ULT : ICmpInst::ICMP_UGE;
  return Builder.CreateICmp(NewPred, NewAdd, Y);
}
CODEEOF"}

