      // So we want Y on the left, (X - C) on the right.
      if (AddPred == ICmpInst::ICMP_UGT) {
        std::swap(Y, AddOp);
        AddPred = ICmpInst::getSwappedPredicate(AddPred);
        IsAddPredSwapped = true;
      }
    }
  } else if (AddPred == ICmpInst::ICMP_UGE || AddPred == ICmpInst::ICMP_UGT) {
    // These predicates have the "greater" sense, so the value is on the right.
    // We want Y on the left for ult, and (X - C) on the left for ule.
    if (IsAnd) {
      // For AND: need uge.
      // So we want Y on the left, (X - C) on the right.
      if (AddPred == ICmpInst::ICMP_ULE) {
        std::swap(Y, AddOp);
        AddPred = ICmpInst::getSwappedPredicate(AddPred);
        IsAddPredSwapped = true;
      }
    } else {
      // For OR: need ult, which is swapped ugt.
      // So we want (X - C) on the left, Y on the right.
      if (AddPred == ICmpInst::ICMP_UGT) {
        std::swap(Y, AddOp);
        AddPred = ICmpInst::getSwappedPredicate(AddPred);
        IsAddPredSwapped = true;
      }
    }
  }

  // Now check the predicate.
  if (IsAnd && AddPred != ICmpInst::ICMP_UGE)
    return nullptr;
  if (!IsAnd && AddPred != ICmpInst::ICMP_ULT)
    return nullptr;

  // Check that AddOp is (X + (-C)), i.e., X - C.
  Value *X2;
  const APInt *AddC;
  if (!match(AddOp, m_Add(m_Value(X2), m_APInt(AddC))) || X2 != X)
    return nullptr;

  // Check that AddC == -C.
  if (*AddC != -(*C))
    return nullptr;

  // Require at least one use to allow the fold.
  if (!EqICmp->hasOneUse() && !AddICmp->hasOneUse())
    return nullptr;

  // Fold to (icmp ugt/ule Y, (X - C - 1)) or (icmp ule/ugt (X - C - 1), Y).
  Type *Ty = X->getType();
  APInt NewC = *AddC - 1;
  Value *NewAdd = Builder.CreateAdd(X, ConstantInt::get(Ty, NewC));

