    // (icmp ne X, C) & (icmp uge Y, (X - C)) -> icmp ugt Y, (X - C - 1)
    return Builder.CreateICmp(ICmpInst::ICMP_UGT, Y, NewAdd);
  } else {
    // (icmp eq X, C) | (icmp ult Y, (X - C)) -> icmp ule Y, (X - C - 1)
    return Builder.CreateICmp(ICmpInst::ICMP_ULE, Y, NewAdd);
  }
